fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val allowedBusiness = listOf("electronics", "grocery", "pharmacy", "restaurant")
    val valid = mutableListOf<Pair<String, String>>()

    for (i in code.indices) {
        val c = code[i]
        val bl = businessLine[i]
        val active = isActive[i]

        if (c.isNotEmpty() && c.matches(Regex("[a-zA-Z0-9_]+")) && allowedBusiness.contains(bl) && active) {
            valid.add(Pair(c, bl))
        }
    }

    val sortedList = valid.sortedWith(compareBy({ it -> allowedBusiness.indexOf(it.second) }, { it -> it.first }))
    return sortedList.map { it.first }.toTypedArray()
}
