import re

def solve(code: list[str], businessLine: list[str], isActive: list[bool]) -> list[str]:
    valid = []
    allowed_business = {"electronics", "grocery", "pharmacy", "restaurant"}
    business_order = {"electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3}
    for i in range(len(code)):
        c = code[i]
        bl = businessLine[i]
        active = isActive[i]
        if re.fullmatch(r'^[a-zA-Z0-9_]+$', c) is None:
            continue
        if bl not in allowed_business:
            continue
        if not active:
            continue
        valid.append((c, bl))
    valid_sorted = sorted(valid, key=lambda x: (business_order[x[1]], x[0]))
    return [x[0] for x in valid_sorted]
